// Script Continued Below
function onLoad() {

	if(g_scratchpad.SNAttachmentsON == false && (typeof spModal == 'undefined')){

		g_form.hideRelatedList('REL:b9edf0ca0a0a0b010035de2d6b579a03'); //'Attachments';
		g_form.hideRelatedList('REL:433a6f8b1bba4450358efd16dc4bcbe1'); //'Shared Attachments';
		// STRY0080143 - RAJ this did not work and errored out preventing code below from running
		//               The attachment manager appears to be gone, so something else removed this.
		//document.getElementById('header_attachment').style.display = 'none';
		//document.getElementById('header_attachment_line').style.display = 'none';

	}
	// STRY0080195  - hide the platform sections for DocIntegrator if DocIntagrator is turned off or the form being opened is a portal form
	if(g_scratchpad.docIntDocumentsOn == false || (typeof spModal != 'undefined')){
		g_form.setSectionDisplay('shared_documents',false);
		g_form.setSectionDisplay('my_documents',false);
	}
	// if Shared documents is disabled, remove section on platform
	if(g_scratchpad.sharedDocumentsFolder == false || (typeof spModal != 'undefined')){
		g_form.setSectionDisplay('shared_documents',false);
	}
	// STRY0086644 
	if(g_form.isNewRecord()){
		g_form.setSectionDisplay('my_documents',false);
		g_form.setSectionDisplay('shared_documents',false);
	}

}
